import { Component } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router, RouterLink } from '@angular/router';
import { FormBuilder, FormGroup, ReactiveFormsModule, Validators } from '@angular/forms';
import { MatCardModule } from '@angular/material/card';
import { MatButtonModule } from '@angular/material/button';
import { MatIconModule } from '@angular/material/icon';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatInputModule } from '@angular/material/input';
import { MatSelectModule } from '@angular/material/select';
import { MatProgressSpinnerModule } from '@angular/material/progress-spinner';
import { UsersService, CreateUserPayload } from '../../services/users.service';

@Component({
  selector: 'app-register',
  standalone: true,
  imports: [
    CommonModule,
    RouterLink,
    ReactiveFormsModule,
    MatCardModule,
    MatButtonModule,
    MatIconModule,
    MatFormFieldModule,
    MatInputModule,
    MatSelectModule,
    MatProgressSpinnerModule,
  ],
  templateUrl: './register.component.html',
  styleUrl: './register.component.scss',
})
export class RegisterComponent {
  form: FormGroup;
  loading = false;
  errorMessage = '';

  roles: { value: number; label: string }[] = [
    { value: 0, label: 'Manager' },
    { value: 1, label: 'Invitado' },
  ];
  estados: { value: boolean; label: string }[] = [
    { value: true, label: 'Activo' },
    { value: false, label: 'Inactivo' },
  ];

  constructor(
    private fb: FormBuilder,
    private router: Router,
    private usersService: UsersService
  ) {
    this.form = this.fb.group({
      correo: ['', [Validators.required, Validators.email]],
      contraseña: ['', [Validators.required, Validators.minLength(4)]],
      nombreCompleto: ['', [Validators.required, Validators.minLength(2)]],
      rol: [1, [Validators.required]], // Invitado por defecto
      telefono: [''],
      activo: [true, [Validators.required]],
    });
  }

  onSubmit(): void {
    this.errorMessage = '';
    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }

    const raw = this.form.value;
    const payload: CreateUserPayload = {
      correo: raw.correo.trim(),
      contraseña: raw.contraseña,
      nombreCompleto: raw.nombreCompleto.trim(),
      rol: Number(raw.rol),
      telefono: raw.telefono?.trim() || undefined,
      activo: Boolean(raw.activo),
    };

    this.loading = true;
    this.usersService.createUser(payload).subscribe({
      next: () => {
        this.loading = false;
        this.router.navigate(['/login']);
      },
      error: (err) => {
        this.loading = false;
        this.errorMessage =
          err?.error?.message ?? err?.message ?? 'No se pudo crear el usuario.';
      },
    });
  }
}
<div class="register-page">
  <mat-card class="register-card">
    <mat-card-header>
      <mat-card-title>ProBook</mat-card-title>
      <mat-card-subtitle>Crear cuenta</mat-card-subtitle>
    </mat-card-header>
    <mat-card-content>
      <form [formGroup]="form" (ngSubmit)="onSubmit()">
        <mat-form-field appearance="outline" class="full-width">
          <mat-label>Correo electrónico</mat-label>
          <input matInput type="email" formControlName="correo" placeholder="usuario@ejemplo.com" />
          <mat-error *ngIf="form.get('correo')?.hasError('required')">El correo es obligatorio</mat-error>
          <mat-error *ngIf="form.get('correo')?.hasError('email')">Correo no válido</mat-error>
        </mat-form-field>

        <mat-form-field appearance="outline" class="full-width">
          <mat-label>Contraseña</mat-label>
          <input matInput type="password" formControlName="contraseña" placeholder="••••••••" />
          <mat-error *ngIf="form.get('contraseña')?.hasError('required')">La contraseña es obligatoria</mat-error>
          <mat-error *ngIf="form.get('contraseña')?.hasError('minlength')">Mínimo 4 caracteres</mat-error>
        </mat-form-field>

        <mat-form-field appearance="outline" class="full-width">
          <mat-label>Nombre completo</mat-label>
          <input matInput formControlName="nombreCompleto" placeholder="Ej. Roberto Carlos" />
          <mat-error *ngIf="form.get('nombreCompleto')?.hasError('required')">El nombre es obligatorio</mat-error>
          <mat-error *ngIf="form.get('nombreCompleto')?.hasError('minlength')">Mínimo 2 caracteres</mat-error>
        </mat-form-field>

        <mat-form-field appearance="outline" class="full-width">
          <mat-label>Rol</mat-label>
          <mat-select formControlName="rol">
            @for (r of roles; track r.value) {
              <mat-option [value]="r.value">{{ r.label }}</mat-option>
            }
          </mat-select>
        </mat-form-field>

        <mat-form-field appearance="outline" class="full-width">
          <mat-label>Teléfono</mat-label>
          <input matInput formControlName="telefono" placeholder="Ej. 95847521" />
        </mat-form-field>

        <mat-form-field appearance="outline" class="full-width">
          <mat-label>Estado</mat-label>
          <mat-select formControlName="activo">
            @for (e of estados; track e.value) {
              <mat-option [value]="e.value">{{ e.label }}</mat-option>
            }
          </mat-select>
        </mat-form-field>

        <p class="error-msg" *ngIf="errorMessage">{{ errorMessage }}</p>

        <button mat-flat-button color="primary" type="submit" class="full-width submit-btn" [disabled]="loading">
          <mat-spinner *ngIf="loading" diameter="24" class="btn-spinner"></mat-spinner>
          <mat-icon *ngIf="!loading" aria-hidden="true">person_add</mat-icon>
          <span *ngIf="!loading">Registrar</span>
        </button>
      </form>
    </mat-card-content>
    <mat-card-actions class="card-footer">
      <a mat-button routerLink="/login">
        <mat-icon aria-hidden="true">login</mat-icon>
        Volver al login
      </a>
    </mat-card-actions>
  </mat-card>
</div>
